import { useState } from "react";

const FORMSPREE_URL = "https://formspree.io/f/YOUR_FORM_ID"; // ← replace with your Formspree ID

/* ── tiny hook for scroll-based nav shadow ── */
function useScrolled() {
  const [scrolled, setScrolled] = useState(false);
  if (typeof window !== "undefined") {
    window.addEventListener("scroll", () => setScrolled(window.scrollY > 20), { passive: true });
  }
  return scrolled;
}

export default function KaneIntelGroup() {
  const [form, setForm] = useState({ name: "", email: "", company: "", message: "" });
  const [status, setStatus] = useState("idle"); // idle | sending | success | error
  const [errorMsg, setErrorMsg] = useState("");

  const update = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  async function handleSubmit() {
    const { name, email, company, message } = form;
    if (!name || !email || !message) {
      setErrorMsg("Please fill in your name, email, and message.");
      setStatus("error");
      return;
    }
    setStatus("sending");
    setErrorMsg("");

    try {
      const res = await fetch(FORMSPREE_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json", "Accept": "application/json" },
        body: JSON.stringify({
          name,
          email,
          company: company || "Not provided",
          message,
          _subject: `New KaneIntel Inquiry from ${name}`,
          _replyto: email,
        }),
      });

      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        throw new Error(errData?.error || `Submission failed (${res.status})`);
      }

      setStatus("success");
      setForm({ name: "", email: "", company: "", message: "" });
    } catch (err) {
      setErrorMsg(err.message || "Something went wrong. Please try again.");
      setStatus("error");
    }
  }

  return (
    <div style={styles.root}>
      <style>{css}</style>

      {/* NAV */}
      <nav style={styles.nav}>
        <div style={styles.logoWrap}><img src="data:image/jpeg;base64," alt="KaneIntel Logo" style={{width:38,height:38,objectFit:"contain",filter:"drop-shadow(0 0 6px rgba(0,212,255,0.5))",flexShrink:0}}/><div style={styles.logo}>Kane<span style={styles.logoCyan}>Intel</span></div></div>
        <ul style={styles.navLinks}>
          {["Services", "Process", "Why Us", "Contact"].map((l) => (
            <li key={l}><span onClick={() => document.getElementById(l.toLowerCase().replace(" ","") === "why us" ? "whyus" : l.toLowerCase().replace(" ","")).scrollIntoView({behavior:"smooth"})} style={{...styles.navLink, cursor:"pointer"}} className="nav-link">{l}</span></li>
          ))}
        </ul>
        <span onClick={() => document.getElementById("contact").scrollIntoView({behavior:"smooth"})} style={{...styles.navCta, cursor:"pointer"}} className="nav-cta">Get a Free Consult</span>
      </nav>

      {/* HERO */}
      <div style={styles.hero}>
        <div style={styles.heroBg} />
        <div style={styles.heroContent}>
          <div style={styles.badge}><span style={styles.badgeDot} className="pulse" />Next-Generation AI Solutions</div>
          <h1 style={styles.h1}>Turn Intelligence<br/>Into <span className="gradient-text">Competitive Advantage</span></h1>
          <p style={styles.heroP}>KaneIntel builds custom AI systems that automate your operations, unlock hidden insights, and scale your business—without the complexity.</p>
          <div style={styles.heroBtns}>
            <span onClick={() => document.getElementById("contact").scrollIntoView({behavior:"smooth"})} style={{...styles.btnPrimary, cursor:"pointer"}} className="btn-primary">Start Your AI Journey →</span>
            <span onClick={() => document.getElementById("services").scrollIntoView({behavior:"smooth"})} style={{...styles.btnSecondary, cursor:"pointer"}} className="btn-secondary">See What We Do</span>
          </div>
        </div>
      </div>

      {/* STATS */}
      <div style={styles.stats}>
        {[["10×","Average Efficiency Gains"],["48hr","Rapid Proof of Concept"],["100%","Custom-Built for Your Business"],["24/7","AI Systems, Always On"]].map(([n,l]) => (
          <div key={n} style={styles.stat}>
            <div style={styles.statNum} className="gradient-text">{n}</div>
            <div style={styles.statLabel}>{l}</div>
          </div>
        ))}
      </div>

      {/* SERVICES */}
      <section id="services" style={styles.section}>
        <div style={styles.sectionTag}>What We Build</div>
        <h2 style={styles.h2}>AI Solutions Engineered for Real Results</h2>
        <p style={{...styles.sub, maxWidth:"100%"}}>We don't sell off-the-shelf software. We architect intelligent systems tailored to your unique workflows and goals.</p>
        <div style={styles.servicesGrid}>
          {[
            ["🤖","AI Automation","Eliminate repetitive tasks and streamline complex workflows with intelligent automation that learns and adapts to your business processes."],
            ["💬","Custom AI Agents","Deploy autonomous AI agents that handle customer service, lead qualification, scheduling, and internal operations—24/7 without fatigue."],
            ["📊","Business Intelligence","Transform your raw data into clear, actionable intelligence with AI-powered dashboards, forecasting models, and predictive analytics."],
            ["🔗","AI Integration","Seamlessly embed AI capabilities into your existing tools—CRM, ERP, e-commerce platforms—without disrupting your operations."],
            ["🧠","LLM Fine-Tuning","Train large language models on your proprietary data so your AI speaks your brand's language and stays accurate."],
            ["🛡️","AI Strategy & Consulting","Our experts audit your business, identify the highest-ROI AI opportunities, and build a clear roadmap to get there."],
          ].map(([icon, title, desc]) => (
            <div key={title} style={styles.card} className="card">
              <div style={styles.cardIcon}>{icon}</div>
              <h3 style={styles.cardTitle}>{title}</h3>
              <p style={styles.cardDesc}>{desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* PROCESS */}
      <section id="process" style={{ ...styles.section, background: "rgba(10,22,40,0.4)", borderRadius: 24 }}>
        <div style={styles.sectionTag}>How It Works</div>
        <h2 style={styles.h2}>From Discovery to<br/>Deployed in Weeks</h2>
        <p style={styles.sub}>A proven four-step process that de-risks AI adoption and delivers measurable outcomes fast.</p>
        <div>
          {[
            ["01","Discovery Call","We start with a free 30-minute consultation to understand your business goals, current pain points, and where AI can make the biggest difference."],
            ["02","Strategy & Blueprint","Our team maps out a custom AI roadmap with clear deliverables, timelines, and projected ROI—before we write a single line of code."],
            ["03","Build & Test","We develop your AI solution in rapid sprints, sharing progress along the way. Rigorous testing ensures everything performs in your real-world environment."],
            ["04","Deploy & Optimise","We launch your AI system, train your team, and monitor performance. Ongoing optimisation means your AI gets smarter over time."],
          ].map(([num, title, desc], i, arr) => (
            <div key={num} style={{ ...styles.step, borderBottom: i < arr.length - 1 ? "1px solid rgba(15,111,255,0.08)" : "none" }}>
              <div style={styles.stepNum} className="gradient-text-fade">{num}</div>
              <div><h3 style={styles.stepTitle}>{title}</h3><p style={styles.stepDesc}>{desc}</p></div>
            </div>
          ))}
        </div>
      </section>

      {/* WHY US */}
      <section id="whyus" style={styles.section}>
        <div style={styles.sectionTag}>Why KaneIntel</div>
        <h2 style={styles.h2}>The Agency That Delivers,<br/>Not Just Promises</h2>
        <p style={styles.sub}>Hundreds of AI agencies talk a big game. We let results do the talking.</p>
        <div style={styles.whyGrid}>
          {[
            ["⚡","Fast Time-to-Value","Working prototypes in 48 hours. Full deployments in weeks. Your ROI starts sooner."],
            ["🎯","Business-First Thinking","We understand your industry and build AI that solves real business problems."],
            ["🔒","Secure & Compliant","Enterprise-grade data security baked in from day one. Your data stays yours."],
            ["📈","Proven ROI Focus","Every project starts with clear success metrics. We build to hit targets."],
            ["🤝","True Partnership","We work alongside your team, transfer knowledge, and stick around after launch."],
            ["🔧","Fully Custom","No templates. Every solution is architected from scratch for your exact needs."],
          ].map(([icon, title, desc]) => (
            <div key={title} style={styles.whyCard}>
              <div style={styles.whyIcon}>{icon}</div>
              <h4 style={styles.whyTitle}>{title}</h4>
              <p style={styles.whyDesc}>{desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* CTA BANNER */}
      <div style={styles.ctaBanner}>
        <div style={styles.sectionTag}>Ready to Get Started?</div>
        <h2 style={{ ...styles.h2, marginBottom: 16 }}>Let's Build Your AI Advantage</h2>
        <p style={{ color: "#a8b8cc", maxWidth: 480, margin: "0 auto 36px" }}>Book a free strategy session and discover exactly how AI can transform your business—no commitment required.</p>
        <span onClick={() => document.getElementById("contact").scrollIntoView({behavior:"smooth"})} style={{...styles.btnPrimary, cursor:"pointer"}} className="btn-primary">Book Your Free Consultation →</span>
      </div>

      {/* CONTACT */}
      <section id="contact" style={{ ...styles.section, textAlign: "center" }}>
        <div style={styles.sectionTag}>Contact Us</div>
        <h2 style={styles.h2}>Let's Talk</h2>
        <p style={{ ...styles.sub, margin: "0 auto 40px" }}>Tell us about your project and we'll get back to you within one business day.</p>

        <div style={styles.contactForm}>
          {[
            { name: "name", placeholder: "Your Name", type: "text" },
            { name: "email", placeholder: "Business Email", type: "email" },
            { name: "company", placeholder: "Company Name (optional)", type: "text" },
          ].map((f) => (
            <input
              key={f.name}
              name={f.name}
              type={f.type}
              placeholder={f.placeholder}
              value={form[f.name]}
              onChange={update}
              style={styles.input}
              className="form-input"
              disabled={status === "sending"}
            />
          ))}
          <textarea
            name="message"
            placeholder="Tell us about your business and what you'd like AI to help with…"
            value={form.message}
            onChange={update}
            style={styles.textarea}
            className="form-input"
            disabled={status === "sending"}
          />

          {status === "error" && (
            <div style={styles.errorBox}>⚠️ {errorMsg}</div>
          )}

          {status === "success" ? (
            <div style={styles.successBox}>
              ✅ Message sent! Check your Gmail inbox — we'll follow up within one business day.
            </div>
          ) : (
            <button
              onClick={handleSubmit}
              style={{ ...styles.submitBtn, opacity: status === "sending" ? 0.7 : 1 }}
              className="btn-primary"
              disabled={status === "sending"}
            >
              {status === "sending" ? "Sending via Gmail…" : "Send Message →"}
            </button>
          )}
        </div>
      </section>

      {/* FOOTER */}
      <footer style={styles.footer}>
        <div style={styles.logoWrap}><img src="data:image/jpeg;base64," alt="KaneIntel Logo" style={{width:38,height:38,objectFit:"contain",filter:"drop-shadow(0 0 6px rgba(0,212,255,0.5))",flexShrink:0}}/><div style={styles.logo}>Kane<span style={styles.logoCyan}>Intel</span></div></div>
        <div style={{ color: "#a8b8cc", fontSize: "0.85rem" }}>© 2026 KaneIntel. All rights reserved.</div>
        <div style={{ display: "flex", gap: 24 }}>
          {["Privacy","Terms","Contact"].map((l) => (
            <span key={l} onClick={() => l === "Contact" && document.getElementById("contact").scrollIntoView({behavior:"smooth"})} style={{ color: "#a8b8cc", textDecoration: "none", fontSize: "0.85rem", cursor: l === "Contact" ? "pointer" : "default" }}>{l}</span>
          ))}
        </div>
      </footer>
    </div>
  );
}

